'use client';

import { useState, useEffect, useCallback } from 'react';
import { 
  Play, 
  Square, 
  Clock, 
  CalendarDays, 
  Search, 
  ArrowRight,
  TrendingUp,
  UserCheck
} from 'lucide-react';
import { useStore } from '@/store/useStore';
import { apiClient } from '@/lib/api-client';

interface AttendanceRecord {
  id: string;
  checkIn: string;
  checkOut: string | null;
  totalHours: number | null;
  attendanceStatus: 'PRESENT' | 'LATE' | 'ABSENT' | 'HALF_DAY';
  date: string;
}

export default function AttendancePage() {
  const { user } = useStore();
  const [logs, setLogs] = useState<AttendanceRecord[]>([]);
  const [loading, setLoading] = useState(true);
  const [isCheckedIn, setIsCheckedIn] = useState(false);
  const [todayRecord, setTodayRecord] = useState<AttendanceRecord | null>(null);
  
  // Running timer state
  const [elapsedTime, setElapsedTime] = useState('00:00:00');
  const [timerIntervalId, setTimerIntervalId] = useState<NodeJS.Timeout | null>(null);

  // Month filters
  const [month, setMonth] = useState(String(new Date().getMonth() + 1));
  const [year, setYear] = useState(String(new Date().getFullYear()));

  const fetchAttendance = useCallback(() => {
    if (!user?.employeeId) return;
    setLoading(true);
    apiClient.get('/api/attendance', {
      employeeId: user.employeeId,
      month: parseInt(month),
      year: parseInt(year)
    })
      .then(res => {
        if (res.success) {
          setLogs(res.data);
          
          // Check if checked in today
          const todayStr = new Date('2026-05-26').toDateString(); // Mocked current time today
          const todayLog = res.data.find((log: AttendanceRecord) => 
            new Date(log.date).toDateString() === todayStr
          );

          if (todayLog) {
            setTodayRecord(todayLog);
            if (todayLog.checkOut === null) {
              setIsCheckedIn(true);
            } else {
              setIsCheckedIn(false);
            }
          } else {
            setTodayRecord(null);
            setIsCheckedIn(false);
          }
        }
      })
      .catch(err => console.error(err))
      .finally(() => setLoading(false));
  }, [user, month, year]);

  useEffect(() => {
    fetchAttendance();
  }, [fetchAttendance]);

  // Handle live timer update
  useEffect(() => {
    if (isCheckedIn && todayRecord) {
      const interval = setInterval(() => {
        const checkInTime = new Date(todayRecord.checkIn).getTime();
        const diffMs = Date.now() - checkInTime;
        const diffHrs = Math.floor(diffMs / 3600000);
        const diffMins = Math.floor((diffMs % 3600000) / 60000);
        const diffSecs = Math.floor((diffMs % 60000) / 1000);

        setElapsedTime(
          `${String(diffHrs).padStart(2, '0')}:${String(diffMins).padStart(2, '0')}:${String(diffSecs).padStart(2, '0')}`
        );
      }, 1000);
      
      setTimerIntervalId(interval);
      return () => clearInterval(interval);
    } else {
      if (timerIntervalId) {
        clearInterval(timerIntervalId);
        setTimerIntervalId(null);
      }
      setElapsedTime('00:00:00');
    }
  }, [isCheckedIn, todayRecord]);

  const handleCheckIn = async () => {
    if (!user?.employeeId) return;
    try {
      const res = await apiClient.post('/api/attendance/check-in', { employeeId: user.employeeId });
      if (res.success) {
        fetchAttendance();
      }
    } catch (err) {
      console.error(err);
    }
  };

  const handleCheckOut = async () => {
    if (!user?.employeeId) return;
    try {
      const res = await apiClient.post('/api/attendance/check-out', { employeeId: user.employeeId });
      if (res.success) {
        fetchAttendance();
      }
    } catch (err) {
      console.error(err);
    }
  };

  const formatTime = (isoString: string | null) => {
    if (!isoString) return '--';
    const date = new Date(isoString);
    return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' });
  };

  const formatDate = (isoString: string) => {
    const date = new Date(isoString);
    return date.toLocaleDateString('en-US', { weekday: 'short', month: 'short', day: 'numeric', year: 'numeric' });
  };

  return (
    <div className="space-y-6">
      {/* Page Header */}
      <div>
        <h2 className="text-xl font-black text-[var(--text-primary)]">Attendance Tracker</h2>
        <p className="text-xs text-[var(--text-muted)] mt-0.5">Log working hours, breaks, and shifts presence</p>
      </div>

      {/* Main Row: Check-In widget & Quick Stats */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
        
        {/* Check In Widget */}
        <div className="glass-card p-6 md:col-span-2 flex flex-col md:flex-row items-center justify-between gap-6 hover:transform-none">
          <div className="space-y-3 w-full md:w-auto text-center md:text-left">
            <div className="inline-flex items-center gap-2 rounded-xl bg-blue-50 dark:bg-blue-950/20 px-3 py-1.5 text-xs font-semibold text-blue-600 dark:text-blue-400">
              <Clock size={14} />
              <span>Shift: General 9:00 AM - 6:00 PM</span>
            </div>
            
            <div className="space-y-1">
              <h3 className="text-xl font-extrabold text-[var(--text-primary)]">
                {isCheckedIn ? 'You are Checked In' : 'Not Checked In Yet'}
              </h3>
              <p className="text-xs text-[var(--text-secondary)] font-medium">
                {isCheckedIn 
                  ? `Checked in at ${formatTime(todayRecord?.checkIn || '')}`
                  : 'Start your shift timer below to log your working hours.'
                }
              </p>
            </div>

            {/* Timer view */}
            {isCheckedIn && (
              <div className="text-3xl font-black font-mono text-blue-600 dark:text-blue-400 tracking-tight mt-3">
                {elapsedTime}
              </div>
            )}
          </div>

          {/* Button actions */}
          <div className="shrink-0 w-full md:w-auto">
            {isCheckedIn ? (
              <button
                onClick={handleCheckOut}
                className="flex w-full md:w-auto h-12 items-center justify-center gap-2 rounded-xl bg-red-600 hover:bg-red-500 text-white font-bold text-sm px-6 shadow-md shadow-red-600/10 active:scale-99 transition-all cursor-pointer"
              >
                <Square size={16} fill="white" />
                Check Out Shift
              </button>
            ) : (
              <button
                onClick={handleCheckIn}
                disabled={todayRecord !== null && todayRecord.checkOut !== null}
                className="flex w-full md:w-auto h-12 items-center justify-center gap-2 rounded-xl bg-blue-600 hover:bg-blue-500 text-white font-bold text-sm px-6 shadow-md shadow-blue-600/10 active:scale-99 transition-all disabled:opacity-40 cursor-pointer"
              >
                <Play size={16} fill="white" />
                Check In Shift
              </button>
            )}
            
            {todayRecord !== null && todayRecord.checkOut !== null && (
              <p className="text-[10px] text-center text-slate-400 font-bold mt-2">
                Shift logged for today. Check out complete.
              </p>
            )}
          </div>
        </div>

        {/* Small Analytics mini-card */}
        <div className="glass-card p-6 flex flex-col justify-between hover:transform-none">
          <div className="flex h-10 w-10 items-center justify-center rounded-xl bg-blue-50 dark:bg-blue-950/20 text-blue-600 dark:text-blue-400">
            <UserCheck size={20} />
          </div>
          
          <div className="space-y-1.5 mt-6">
            <span className="text-[10px] font-bold text-[var(--text-muted)] uppercase tracking-wider">Attendance Score</span>
            <div className="flex items-end justify-between">
              <h3 className="text-2xl font-black text-[var(--text-primary)]">94.2%</h3>
              <span className="inline-flex items-center gap-0.5 text-[10px] font-bold text-emerald-600 dark:text-emerald-400">
                <TrendingUp size={10} />
                +3.7%
              </span>
            </div>
            <p className="text-[10px] text-[var(--text-muted)] font-bold uppercase tracking-wider">Present: 21 days | Late: 1 day</p>
          </div>
        </div>

      </div>

      {/* Query filters row */}
      <div className="glass-card p-4 flex gap-4 items-center justify-between">
        <div className="flex items-center gap-2">
          <CalendarDays size={16} className="text-blue-500" />
          <span className="font-bold text-xs text-[var(--text-primary)]">Log History Filters</span>
        </div>

        <div className="flex gap-2">
          <select 
            value={month} 
            onChange={(e) => setMonth(e.target.value)}
            className="h-9 px-3 rounded-xl border border-[var(--card-border)] bg-[var(--card-bg)] text-xs text-[var(--text-primary)] focus:outline-none focus:border-blue-500"
          >
            <option value="1">January</option>
            <option value="2">February</option>
            <option value="3">March</option>
            <option value="4">April</option>
            <option value="5">May</option>
            <option value="6">June</option>
            <option value="7">July</option>
            <option value="8">August</option>
            <option value="9">September</option>
            <option value="10">October</option>
            <option value="11">November</option>
            <option value="12">December</option>
          </select>
          <select 
            value={year} 
            onChange={(e) => setYear(e.target.value)}
            className="h-9 px-3 rounded-xl border border-[var(--card-border)] bg-[var(--card-bg)] text-xs text-[var(--text-primary)] focus:outline-none focus:border-blue-500"
          >
            <option value="2025">2025</option>
            <option value="2026">2026</option>
            <option value="2027">2027</option>
          </select>
        </div>
      </div>

      {/* History logs table */}
      <div className="glass-card overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="border-b border-[var(--card-border)] bg-slate-50/50 dark:bg-slate-900/10">
                <th className="px-6 py-3.5 text-[10px] font-bold text-[var(--text-muted)] uppercase tracking-wider">Date</th>
                <th className="px-6 py-3.5 text-[10px] font-bold text-[var(--text-muted)] uppercase tracking-wider">Check In</th>
                <th className="px-6 py-3.5 text-[10px] font-bold text-[var(--text-muted)] uppercase tracking-wider">Check Out</th>
                <th className="px-6 py-3.5 text-[10px] font-bold text-[var(--text-muted)] uppercase tracking-wider">Total Hours</th>
                <th className="px-6 py-3.5 text-[10px] font-bold text-[var(--text-muted)] uppercase tracking-wider">Status</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-[var(--card-border)]">
              {loading ? (
                <tr>
                  <td colSpan={5} className="px-6 py-12 text-center text-xs text-[var(--text-muted)]">
                    <div className="flex flex-col items-center justify-center gap-2">
                      <div className="h-6 w-6 animate-spin rounded-full border-2 border-blue-200 border-t-blue-600"></div>
                      <span>Loading attendance history...</span>
                    </div>
                  </td>
                </tr>
              ) : logs.length === 0 ? (
                <tr>
                  <td colSpan={5} className="px-6 py-12 text-center text-xs text-[var(--text-muted)] font-medium">
                    No attendance logs recorded for this month
                  </td>
                </tr>
              ) : (
                logs.map((log) => (
                  <tr key={log.id} className="hover:bg-slate-50/50 dark:hover:bg-slate-900/10 transition-colors">
                    <td className="px-6 py-4 text-xs font-bold text-[var(--text-primary)]">
                      {formatDate(log.date)}
                    </td>
                    <td className="px-6 py-4 text-xs text-[var(--text-secondary)] font-medium">
                      {formatTime(log.checkIn)}
                    </td>
                    <td className="px-6 py-4 text-xs text-[var(--text-secondary)] font-medium">
                      {formatTime(log.checkOut)}
                    </td>
                    <td className="px-6 py-4 text-xs font-bold text-[var(--text-primary)]">
                      {log.totalHours ? `${log.totalHours.toFixed(2)} hrs` : '--'}
                    </td>
                    <td className="px-6 py-4">
                      <span 
                        className={`inline-flex items-center rounded-full px-2 py-0.5 text-[10px] font-semibold border
                          ${log.attendanceStatus === 'PRESENT' 
                            ? 'bg-emerald-50 dark:bg-emerald-950/20 text-emerald-600 dark:text-emerald-400 border-emerald-100 dark:border-emerald-900/10' 
                            : log.attendanceStatus === 'LATE'
                            ? 'bg-amber-50 dark:bg-amber-950/20 text-amber-600 dark:text-amber-400 border-amber-100 dark:border-amber-900/10'
                            : log.attendanceStatus === 'HALF_DAY'
                            ? 'bg-blue-50 dark:bg-blue-950/20 text-blue-600 dark:text-blue-400 border-blue-100 dark:border-blue-900/10'
                            : 'bg-red-50 dark:bg-red-950/20 text-red-600 dark:text-red-400 border-red-100 dark:border-red-900/10'
                          }
                        `}
                      >
                        {log.attendanceStatus}
                      </span>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}
